#!/bin/sh
# JSON files have been initially generated by this script and have been manually rewritten to improve the generated code or fill missing infomation.
# e.g. statuses are not specified in the v1beta schema.
# use with caution

version=`octl kube kubectl --cluster foo -- get crd nodepools.oks.dev -o json | jq -r '.status.storedVersions[0]'`
