octl kube kubectl --cluster foo -- get crd nodepools.oks.dev -o json | jq --arg version "$version" '{"openapi":"1.0.1","title":"nodepool","version":$version,"components":{"schemas":{"Nodepool": .spec.versions | map(select(.name == $version))[0].schema.openAPIV3Schema}}}' > apis/oks.dev/$version/nodepool.json
