octl kube kubectl --cluster foo -- get crd oosaccesses.oks.dev -o json | jq --arg version "$version" '{"openapi":"1.0.1","title":"oosaccess","version":$version,"components":{"schemas":{"OOSAccess": .spec.versions | map(select(.name == $version))[0].schema.openAPIV3Schema}}}' > apis/oks.dev/$version/oosaccess.json
